            {
              "letter": "B",
              "text": "capacidade de testemunhar."
            },
            {
              "letter": "C",
              "text": "capacidade testamentária."
            },
            {
              "letter": "D",
              "text": "capacidade de votar."
            },
            {
              "letter": "E",
              "text": "capacidade de guarda de menores."
            }
